import clsx from 'clsx';
import React from 'react';
import { Progress } from '../../progress';
import type { UploadFile, UploadProgressProps } from './interface';

export function UploadProgress({
  prefixCls,
  file,
  progressProps,
  className,
  ...htmlProps
}: {
  prefixCls: string;
  file: UploadFile;
  progressProps?: UploadProgressProps;
} & React.HTMLAttributes<HTMLDivElement>) {
  if (file.status === 'uploading' || file.status === 'waiting' || file.status === 'downloading') {
    return (
      <div className={clsx(`${prefixCls}-progress`, className)} data-testid="progress" {...htmlProps}>
        <Progress type="line" showInfo={false} percent={file.percent} strokeWidth={4} {...progressProps} />
      </div>
    );
  }
  return null;
}
